create table dirkspzm32.s_sap_transaction (
    tid           varchar2(32 char) not null enable,
    source_sys    varchar2(10 char) not null enable,
    dest_sys      varchar2(10 char) not null enable,
    direction     varchar2(10 char) not null enable,
    tid_status    varchar2(20 char) not null enable,
    idoc_type     varchar2(30 char),
    message_type  varchar2(30 char),
    error_message varchar2(255 char),
    created       date default sysdate not null enable,
    modified      date
);

alter table dirkspzm32.s_sap_transaction
    add constraint pk_s_sap_transaction primary key ( tid )
        using index enable;


